const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');

// Generate a strong secret key (in production, load from environment variable / secrets manager)
// Minimum 256 bits for HMAC-SHA256
const JWT_SECRET = process.env.JWT_SECRET;

if (!JWT_SECRET || Buffer.byteLength(JWT_SECRET, 'utf8') < 32) {
  throw new Error(
    'JWT_SECRET environment variable must be set and be at least 32 bytes (256 bits) long.'
  );
}

const ISSUER = process.env.JWT_ISSUER || 'my-prototype-api';
const AUDIENCE = process.env.JWT_AUDIENCE || 'my-prototype-client';
const TOKEN_EXPIRY = '15m'; // Short-lived tokens for prototype

// Allowed algorithms — explicitly restrict to prevent algorithm confusion attacks
const ALLOWED_ALGORITHMS = ['HS256'];

/**
 * Middleware: verifyJWT
 *
 * - Extracts the Bearer token from the Authorization header.
 * - Verifies the token using jwt.verify() with strict options:
 *     • Explicit algorithms allowlist (prevents "none" algorithm and RS/HS confusion attacks)
 *     • Issuer validation
 *     • Audience validation
 *     • Expiration is required and validated (ignoreExpiration is explicitly false)
 *     • Clock tolerance of 5 seconds to account for minor clock skew
 * - Attaches decoded user info to req.user on success.
 */
function verifyJWT(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({ error: 'Authorization header is missing.' });
  }

  const parts = authHeader.split(' ');

  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({ error: 'Authorization header must be in the format: Bearer <token>' });
  }

  const token = parts[1];

  if (!token || token.trim() === '') {
    return res.status(401).json({ error: 'Token is empty.' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ALLOWED_ALGORITHMS,   // Strict algorithm allowlist
      issuer: ISSUER,                    // Validate issuer claim
      audience: AUDIENCE,                // Validate audience claim
      ignoreExpiration: false,           // Explicitly enforce expiration
      clockTolerance: 5,                 // 5 seconds tolerance for clock skew
      complete: false,                   // Return only the payload
    });

    // Ensure required claims are present
    if (!decoded.sub) {
      return res.status(401).json({ error: 'Token is missing required "sub" claim.' });
    }

    if (!decoded.iat) {
      return res.status(401).json({ error: 'Token is missing required "iat" claim.' });
    }

    if (!decoded.exp) {
      return res.status(401).json({ error: 'Token is missing required "exp" claim.' });
    }

    // Optional: reject tokens issued too far in the past (even if not yet expired)
    // This limits the window for token replay
    const now = Math.floor(Date.now() / 1000);
    const maxTokenAge = 60 * 60; // 1 hour max age
    if (decoded.iat < now - maxTokenAge) {
      return res.status(401).json({ error: 'Token is too old. Please re-authenticate.' });
    }

    // Attach user info to request
    req.user = {
      id: decoded.sub,
      email: decoded.email || null,
      role: decoded.role || 'user',
      iat: decoded.iat,
      exp: decoded.exp,
    };

    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired.' });
    }
    if (err.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token.' });
    }
    if (err.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token is not yet active.' });
    }
    return res.status(401).json({ error: 'Token verification failed.' });
  }
}

/**
 * Helper: generateToken
 *
 * Creates a signed JWT with proper claims for use in login/auth routes.
 * Includes: sub, email, role, iss, aud, iat, exp, jti (unique token ID to mitigate replay).
 */
function generateToken(user) {
  if (!user || !user.id) {
    throw new Error('User object with an "id" property is required.');
  }

  const payload = {
    sub: user.id,
    email: user.email || null,
    role: user.role || 'user',
    jti: crypto.randomUUID(), // Unique token ID — helps with replay detection / revocation
  };

  return jwt.sign(payload, JWT_SECRET, {
    algorithm: ALLOWED_ALGORITHMS[0],
    expiresIn: TOKEN_EXPIRY,
    issuer: ISSUER,
    audience: AUDIENCE,
  });
}

